import{_ as e,a as t,e as r,f as i,g as p,k as o,i as n,h as l,j as s,l as c,b as d,c as h,d as m}from"./chunks/dev_settings_preview.DVlhR-_b.js";import{d as u,e as _,_ as g,a as b,b as f,c as P}from"./chunks/data_management.DYhhvOmf.js";import{p as q,bh as k,I as y,U as v}from"./chunks/framework.BpabEsSf.js";const O=JSON.parse('{"title":"Обзор интерфейса","description":"","frontmatter":{"title":"Обзор интерфейса","date":"2026-05-01T23:30:00.000Z","permalink":"/guide/overview","categories":["Introduction"],"tags":["Project"]},"headers":[],"relativePath":"ru/01.Guide/01.Introduction/02.Interface Overview.md","filePath":"ru/01.Guide/01.Introduction/02.Interface Overview.md","lastUpdated":null}'),S={name:"ru/01.Guide/01.Introduction/02.Interface Overview.md"};function A(x,a,I,z,M,w){return k(),y("div",null,[...a[0]||(a[0]=[v('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /ru\\01.Guide\\01.Introduction\\02.Interface Overview.md for this page in Markdown format</div><h1 id="обзор-интерфеиса" tabindex="-1">Обзор интерфейса <a class="header-anchor" href="#обзор-интерфеиса" aria-label="Permalink to &quot;Обзор интерфейса&quot;">​</a></h1><h2 id="обзор" tabindex="-1">Обзор <a class="header-anchor" href="#обзор" aria-label="Permalink to &quot;Обзор&quot;">​</a></h2><p>Monica предлагает 7 основных экранов, доступных через нижнюю панель навигации: Менеджер паролей, Двухфакторный аутентификатор (2FA), Кошелек карт, Защищенные заметки, История/Корзина, Генератор паролей и Настройки.</p><p><img src="'+e+'" alt="Overview" loading="lazy"></p><p>Элементы нижней панели навигации можно переупорядочивать или включать/выключать в соответствии с вашими личными предпочтениями.</p><h2 id="управление-панелью-навигации" tabindex="-1">Управление панелью навигации <a class="header-anchor" href="#управление-панелью-навигации" aria-label="Permalink to &quot;Управление панелью навигации&quot;">​</a></h2><p>Вы можете включить только те вкладки, которые вам полезны, сохраняя навигацию чистой и свободной от беспорядка.</p><p><img src="'+t+'" alt="Navigation Management" loading="lazy"></p><p>Давайте сначала рассмотрим экран Менеджера паролей.</p><h2 id="экран-паролеи" tabindex="-1">Экран паролей <a class="header-anchor" href="#экран-паролеи" aria-label="Permalink to &quot;Экран паролей&quot;">​</a></h2><p>Слева направо: главный экран паролей, развернутые карточки сгруппированных элементов, подробные сведения о пароле и интерфейс редактирования/добавления пароля.</p><p>Базовый интерфейс прост и позволяет без особых усилий создавать учетные записи и управлять ими.</p><p><img src="'+r+'" alt="Passwords Screen" loading="lazy"></p><p>Если вы настроите «Общую информацию об аккаунте» в Настройках, она будет автоматически заполняться при создании нового пароля. Вы также можете нажать «Вход через сторонние сервисы» (показано на рисунке 2), чтобы сослаться на другие учетные данные или связать их.</p><p>Верхняя панель экрана Паролей содержит две кнопки: левая открывает нижнюю шторку для управления категориями, а вторая управляет поведением группировки карточек (хотя внешний вид по умолчанию уже оптимизирован).</p><p><img src="'+i+'" alt="Common Info &amp; Categories" loading="lazy"></p><p>Далее идет экран множественного выбора, вызываемый сдвигом карточек вправо.</p><h2 id="интерфеис-множественного-выбора" tabindex="-1">Интерфейс множественного выбора <a class="header-anchor" href="#интерфеис-множественного-выбора" aria-label="Permalink to &quot;Интерфейс множественного выбора&quot;">​</a></h2><p>Свайп вправо активирует режим пакетных действий, вызывая нижнее меню утилит. Слева направо на нем отображаются: счетчик выбранных элементов, выбрать все, добавить в избранное, добавить в категорию и пакетное удаление.</p><p><img src="'+u+'" alt="Multi-Select Screen" loading="lazy"></p><p>Для защиты от случайной потери данных пакетное удаление не ограничивается подтверждением по биометрии. Оно намеренно вызывает защитное всплывающее окно, требующее явного подтверждения намерения для завершения операции.</p><p>Что касается логики взаимодействия, свайп вправо непосредственно по стопке сгруппированных карточек выбирает всю группу целиком. Нажатие на стопку разворачивает ее, позволяя осуществлять детальный выбор отдельных элементов.</p><p>Когда режим множественного выбора отключен, обычный свайп влево по элементу служит триггером удаления. Эта логика удаления свайпом влево применяется как во вкладке «Пароли», так и во вкладке «Аутентификатор».</p><p>Перейдем к экрану 2FA Аутентификатора.</p><h2 id="экран-2fa-аутентификатора" tabindex="-1">Экран 2FA Аутентификатора <a class="header-anchor" href="#экран-2fa-аутентификатора" aria-label="Permalink to &quot;Экран 2FA Аутентификатора&quot;">​</a></h2><p>Макет 2FA Аутентификатора невероятно чистый. Он следует той же механике: свайп вправо для множественного выбора и свайп влево для удаления.</p><p>Нажатие кнопки добавления в правом нижнем углу открывает полную страницу настройки Аутентификатора (рисунки 2 и 3), где вы можете вручную ввести параметры или отсканировать QR-код. Кроме того, вы можете нажать на самую первую иконку на верхней панели инструментов (рисунок 1), чтобы быстро отсканировать QR-код 2FA на лету.</p><p><img src="'+p+'" alt="2FA Authenticator Screen" loading="lazy"></p><p>Нажатие на три точки в правом верхнем углу карточки аутентификатора открывает меню опций для быстрого редактирования, удаления или просмотра исходного QR-кода (идеально подходит для переноса ваших настроек на другие устройства).</p><p>Нажатие в любом месте карточки 2FA мгновенно копирует токен в буфер обмена.</p><h2 id="расширения-аутентификатора" tabindex="-1">Расширения Аутентификатора <a class="header-anchor" href="#расширения-аутентификатора" aria-label="Permalink to &quot;Расширения Аутентификатора&quot;">​</a></h2><p>В меню Настройки -&gt; Расширения функций вы можете включить опцию «Копировать следующий код при истечении срока». Если эта функция активна и вы нажмете на карточку в течение последних 5 секунд обратного отсчета, система интеллектуально скопирует следующий (грядущий) код вместо истекающего.</p><p>Вы также можете включить «Вибрацию аутентификатора», которая вибрирует в такт с финальным 5-секундным отсчетом. Включение отображения уведомлений закрепляет выбранные коды подтверждения внутри шторки уведомлений Android для быстрого поиска (сейчас эта настройка находится в Расширениях и будет перенесена позже).</p><p><img src="'+_+'" alt="Feature Extensions Screen" loading="lazy"></p><p>Далее идет вкладка Генератора.</p><h2 id="генератор-паролеи" tabindex="-1">Генератор паролей <a class="header-anchor" href="#генератор-паролеи" aria-label="Permalink to &quot;Генератор паролей&quot;">​</a></h2><p>Страница Генератора проста и лаконична, на ней сгруппированы четыре различных типа генераторов вместе со специальным экраном истории.</p><p><img src="'+o+'" alt="Generator Screen" loading="lazy"></p><p>Экран Истории записывает все сгенерированные вами конфигурации, гарантируя, что вы никогда не потеряете доступ к аккаунту, если создадите сложный пароль и забудете нажать кнопку сохранения.</p><h2 id="экран-защищенных-заметок" tabindex="-1">Экран защищенных заметок <a class="header-anchor" href="#экран-защищенных-заметок" aria-label="Permalink to &quot;Экран защищенных заметок&quot;">​</a></h2><p>Функция Защищенных заметок не стремится заменить полноценные текстовые редакторы. Она прекрасно работает как защищенное персональное хранилище для резервного копирования конфиденциальной текстовой информации, ключей восстановления и сид-фраз в зашифрованной экосистеме.</p><p><img src="'+n+'" alt="Secure Notes Screen" loading="lazy"></p><p>Далее идет Кошелек карт.</p><h2 id="кошелек-карт" tabindex="-1">Кошелек карт <a class="header-anchor" href="#кошелек-карт" aria-label="Permalink to &quot;Кошелек карт&quot;">​</a></h2><p>Кошелек карт предназначен для хранения финансовых карт и личных удостоверений личности. Он также поддерживает безопасное прикрепление изображений-снимков физических ID, которые можно в любой момент загрузить обратно в локальное хранилище при необходимости.</p><p><img src="'+l+'" alt="Card Wallet Screen" loading="lazy"></p><p>Система сделана простой и практичной. Это настоящее спасение, когда нужно быстро посмотреть номер паспорта, а у вас нет его под рукой или вы не помните его наизусть.</p><p>Давайте посмотрим на вкладку Истории.</p><h2 id="страница-истории" tabindex="-1">Страница истории <a class="header-anchor" href="#страница-истории" aria-label="Permalink to &quot;Страница истории&quot;">​</a></h2><p>Центр Истории разделен на два раздела: «Хронология» и «Корзина».</p><p>Хронология ведет хронологический аудит ваших изменений, позволяя просматривать прошлые редакции, отменять изменения в полях записей или клонировать исторические записи в совершенно новые элементы. Корзина позволяет мгновенно восстановить элементы, которые вы удалили по ошибке.</p><p><img src="'+s+'" alt="History Screen" loading="lazy"></p><p>Теперь давайте изучим панели конфигурации Monica.</p><h2 id="эстетичныи-движок-тем" tabindex="-1">Эстетичный движок тем <a class="header-anchor" href="#эстетичныи-движок-тем" aria-label="Permalink to &quot;Эстетичный движок тем&quot;">​</a></h2><p>Интерфейс полностью построен на принципах дизайна Material 3 (M3). Хотя он изначально извлекает динамические акценты напрямую из ваших системных обоев, Monica также предлагает три различные категории предустановленных тем:</p><h3 id="категория-1-натуральные-темы" tabindex="-1">Категория 1: Натуральные темы <a class="header-anchor" href="#категория-1-натуральные-темы" aria-label="Permalink to &quot;Категория 1: Натуральные темы&quot;">​</a></h3><p>Включает 7 цветовых вариаций: По умолчанию (Default), Океанский синий (Ocean Blue), Закатный оранжевый (Sunset Orange), Лесной зеленый (Forest Green), Технологичный фиолетовый (Tech Purple), Черная мамба (Black Mamba) и Мягкий черно-пурпурный (Soft Black Purple).</p><p><img src="'+g+'" alt="Natural Themes" loading="lazy"></p><p><em>(Интересный факт: Черная мамба не является абсолютно глубоким черным цветом, а Мягкий черно-пурпурный тяготеет к приглушенному тону).</em></p><h3 id="категория-2-пресеты-моне" tabindex="-1">Категория 2: Пресеты Моне <a class="header-anchor" href="#категория-2-пресеты-моне" aria-label="Permalink to &quot;Категория 2: Пресеты Моне&quot;">​</a></h3><p>Включает 6 живописных палитр: Кувшинки (Water Lilies), Впечатление. Восходящее солнце (Impression Sunrise), Японский мостик (The Japanese Bridge), Солодковая команда (Licorice Team), Руанский собор (Rouen Cathedral) и Здание парламента в тумане (Houses of Parliament - Fog).</p><p><img src="'+b+'" alt="Monet Presets" loading="lazy"></p><p>Среди них «Кувшинки» — мой абсолютный фаворит: тема невероятно свежая, мягкая и приятная для глаз.</p><h3 id="категория-3-патчи-catppuccin" tabindex="-1">Категория 3: Патчи Catppuccin <a class="header-anchor" href="#категория-3-патчи-catppuccin" aria-label="Permalink to &quot;Категория 3: Патчи Catppuccin&quot;">​</a></h3><p>Знаменитая и любимая многими цветовая экосистема Catppuccin. Если ваши терминалы, Android Studio и темы IDE используют эту эстетику, вы почувствуете себя как дома.</p><p><img src="'+f+'" alt="Catppuccin Patches" loading="lazy"></p><h2 id="общие-настроики-внешнего-вида" tabindex="-1">Общие настройки внешнего вида <a class="header-anchor" href="#общие-настроики-внешнего-вида" aria-label="Permalink to &quot;Общие настройки внешнего вида&quot;">​</a></h2><p>Меню «Внешний вид» позволяет настроить предпочитаемый язык локализации и переключаться между светлым и темным режимами отображения.</p><p><img src="'+c+'" alt="Appearance Settings" loading="lazy"></p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Если включена функция «Динамическое извлечение цвета из обоев», выбранные цвета предустановленных тем будут переопределены системными. Выключите извлечение цвета из обоев, чтобы применить свои кастомные пресеты!</p></div><h2 id="monica-plus" tabindex="-1">Monica Plus <a class="header-anchor" href="#monica-plus" aria-label="Permalink to &quot;Monica Plus&quot;">​</a></h2><p>Monica Plus — это вариант добровольной поддержки по системе чести; это <strong>не</strong> пейволл, и эта функция не блокирует возможности программного обеспечения. Если у вас нет возможности оставить чаевые, вы можете просто нажать кнопку разблокировки, чтобы активировать все функции бесплатно. Пользуйтесь без забот!</p><p>Более того, принудительная строгая серверная проверка лицензий лишь провоцирует появление неофициальных взломанных версий, которые часто содержат несанкционированные изменения кода или скрытые бэкдоры, что создает серьезные уязвимости для пользователей.</p><p>Далее идут критически важные параметры Безопасности.</p><h2 id="настроика-безопасности" tabindex="-1">Настройка безопасности <a class="header-anchor" href="#настроика-безопасности" aria-label="Permalink to &quot;Настройка безопасности&quot;">​</a></h2><p>Включение функции «Разблокировка по отпечатку пальца» избавляет от повторяющихся запросов мастер-пароля во время стандартных защищенных рабочих процессов. Хотя функция распознавания лиц тестировалась, ее высокая чувствительность приводила к непреднамеренным аутентификациям во время конфиденциальных запросов, поэтому приложение полагается исключительно на безопасные датчики отпечатков пальцев.</p><p>Включение «Защиты от захвата экрана» предотвращает создание снимков экрана или запись экрана в любом месте внутри Monica, защищая ваши учетные данные от фонового вредоносного ПО.</p><p>Здесь вы также можете настроить интервалы автоблокировки приложения, обновить мастер-пароль или задать секретные вопросы. Если вы забудете свой мастер-пароль, не настроив секретные вопросы, ваши данные не подлежат восстановлению, и потребуется полный сброс данных приложения.</p><p>Анализатор безопасности проверяет состояние ваших сохраненных аккаунтов на предмет уязвимых параметров. Этот анализ связывается с безопасным сторонним API Have I Been Pwned (HIBP).</p><p><img src="'+d+'" alt="Security Options" loading="lazy"></p><p>Далее идет область «Управление данными».</p><p><img src="'+P+'" alt="Data Management Controls" loading="lazy"></p><p><em>(Да, вкладка «Расширения» случайно оказалась вложенной сюда, потому что я торопился на встречу с другом в тот день, когда создавал ее! Скоро я проведу рефакторинг ее местоположения).</em></p><p>Это меню отвечает за интеграцию автозаполнения, рабочие процессы синхронизации, переключатели расширений, очистку корзины и мастер-сброс.</p><p>Давайте заглянем в интерфейс Синхронизации и Резервного копирования.</p><p><img src="'+h+'" alt="Sync &amp; Backup View" loading="lazy"></p><p>При экспорте данных с помощью Полного бэкапа повторное нажатие на цель экспорта открывает расширенные параметры для выбора конкретных типов записей. Эта резервная копия соответствует базовой структуре, используемой в автоматизации WebDAV.</p><p>Форматы экспорта включают стандартные структуры KeePass или схемы Aegis Authenticator, что позволяет легко перенести ваши данные в другое программное обеспечение, если Monica вам не подойдет.</p><p>Операции WebDAV поддерживают стандартные резервные копии файлов Monica или синхронизацию, совместимую с KeePass. Эта реализация привносит нативную совместимость с файлами KeePass прямо в Monica! Следующим пунктом в нашей дорожной карте стоит репликация, совместимая с Bitwarden, так как я хочу, чтобы этот инструмент оставался невероятно мощным и универсальным для всех.</p><p>Наконец, у нас есть утилиты для разработчиков.</p><p><img src="'+m+'" alt="Developer Settings &amp; Previews" loading="lazy"></p><p>Вкладка «Параметры разработчика» включает активный терминал логов для отладки. <em>(Есть небольшая ошибка, из-за которой логи в реальном времени не всегда надежно обновляются в окне просмотра. Поскольку я все равно отлаживаю приложение напрямую в Android Studio, я пока не исправил ее, но она находится в моем списке задач).</em></p><p>Вы также можете полностью отключить проверку пароля при запуске для быстрого тестирования.</p><p>В разделе «Предварительный просмотр» предлагаются экспериментальные функции, такие как перетаскиваемые дорожки нижней навигации. Хотя сейчас в этом нет строгой необходимости, это послужит основой для реализации двухрядного дока со свайпами, как только наш набор функций расширится. На данный момент система очень стабильна, так что давайте пока не будем усложнять!</p>',95)])])}const B=q(S,[["render",A]]);export{O as __pageData,B as default};
